function LCityView:InitView(cityType)
    if self._isInitOk then
        return
    end
    self._cityType = cityType

    local mainAdapter = MgrCenter.AdapterMgr:GetAdapter(LevelNames.Main)
    local mapTrans = mainAdapter:GetMapTrans()
    if IsNull(mapTrans) then
        return
    end

    if cityType == CityTypeEnum.city then
        self:InitCityMap(mapTrans)
    end
    self._unitMgr:SetRootNode(self._npcRoot)
    self._eventAreaMgr:SetRootNode(self._npcRoot)

    CtrlCenter.City:SetGuideReady(true)
    FireEvent(EventNames.ON_MAP_GUIDE_READY, {levelName = LevelNames.Main,functionType = FuncIds.City})
    self._isInitOk = true
end

