function LCityView:InitCityMap(mapTrans)
    local mapGo = mapTrans.gameObject
    self._mapGo = mapGo
    self._mapRoot = mapTrans:Find('ShakeRoot/MapRoot').gameObject
    --self._storyBg = mapTrans:Find("ShakeRoot/MapRoot/StoryBg").gameObject
    self._shakeRoot = mapTrans:Find("ShakeRoot").gameObject
    self._npcRoot = mapTrans:Find('ShakeRoot/NpcRoot').gameObject
    self._buildingRoot = mapTrans:Find("ShakeRoot/StaticRoot/Building").gameObject
    self.hudRoot = mapTrans:Find("HUDRoot");
    self.hudCanvasRoot = mapTrans:Find("HUDRoot");
    local fog = mapTrans:Find("ShakeRoot/StaticRoot/Fog/EffectFog")
    local fogCount = fog.childCount
    for i = 1, fogCount do
        local fogObj = fog:GetChild(i - 1)
        self._fogList[checknumber(fogObj.name)] = fogObj
    end
    local rendererList = self._npcRoot:GetComponentsInChildren(typeOfRenderer2d,true)
    local count = rendererList.Length - 1
    for k=0, count do
        local renderer2d = rendererList[k]
        renderer2d.sortingLayerName = LayerMaskNames.Object
        renderer2d:SetRendererOrder(10)
        renderer2d:InitRenderers()
        renderer2d:UpdateRenderersLayer()
        renderer2d:UpdateRenderersOrder()
    end
    self._virtualCamMainGo = mapTrans:Find('ControlRoot/VirtualCameraMain').gameObject
    self._virtualCamMain = self._virtualCamMainGo:GetComponent(typeofCinemachineVirtualCamera)
    self._virtualCamMainTrans = self._virtualCamMainGo.transform
    self._camPosition = self._virtualCamMainTrans.position
    ShowObject(self._virtualCamMainGo, true)
    local cameraFollow = self._virtualCamMainGo:GetComponent(typeofFollowObject)
    self._cameraFollow = cameraFollow
    cameraFollow.Target = nil

    if LxAppHelper.IsEditor() or LxAppHelper.IsWindow() or (LxAppHelper.IsWebGL() and LxAppHelper.IsWebGLRunInOther()) then
        local mouseScrollCheck = self._virtualCamMainGo:GetComponent(typeofMouseScrollCheck)
        if not mouseScrollCheck then
            mouseScrollCheck = self._virtualCamMainGo:AddComponent(typeofMouseScrollCheck)
        end
        mouseScrollCheck.CheckUIBlock = true
        mouseScrollCheck.onScroll = function()
            self:OnMouseScroll()
        end
        self._mouseScrollCheck = mouseScrollCheck
    end

    local buildingConfigRef = GameTable.BuildingConfigRef

    local cameraDefaultRate = buildingConfigRef.cameraDefaultRate
    self._cameraDefaultScale = 7.5
    self._cameraMinRate = buildingConfigRef.cameraMinRate
    self._cameraMaxRate = buildingConfigRef.cameraMaxRate

    local birth = buildingConfigRef.CitySite or {}
    self._camPosition.x =  checknumber(birth[1])
    self._camPosition.y = checknumber(birth[2])

    local border = buildingConfigRef.cityBorder
    self._border = border
    self:UpdateCamRang(cameraDefaultRate)

    self._buildingMgr:SetRootNode(self._buildingRoot,self.hudCanvasRoot)
    self._buildingMgr:InitBuildings()
    self._peopleMgr:InitTrans(mapTrans)
   self._initTimer = MgrCenter.TimerMgr:DelayTime(function()
        if(self._peopleMgr == nil or self._monsterMgr == nil)then
            return
        end
        self._peopleMgr:InitPeoples()
        self._monsterMgr:Init(mapTrans)

    end,self,1)

    self:RefreshFog()
    --self:TestHUD(mapTrans)
end

