function LCityView:OnMouseScroll()
    if self:IsInStoryMode() then return end

    if not self._mouseScrollCheck then
        return
    end
    local delta = self._mouseScrollCheck.ScrollDelta
    local isOverUI = self._mouseScrollCheck:IsOverUI()
    --print("delta mouse scroll "..delta  .." isOverUI ".. tostring(isOverUI))
    if isOverUI then
        return
    end

    --delta 大于0 鼠标向上滚动 ，小于0 鼠标向下滚动
    if delta ~= 0 then
        if(ModuleCenter.Story:IsNewbieRunning())then
            return
        end
        self:ShowBuildHUD()
        self:HideBuildHUD()
        self:SetFollowNil()

        self:ChangeCameraRange(-delta * 2)
        CtrlCenter.Guide:CheckGuideTip()
    end
end
