function LCityView:UpdateCamRang(rate)

    if not self._virtualCamMain then return end

    self._curCameraRate = rate

    local Lens = self._virtualCamMain.m_Lens
    if Lens.Orthographic then
        Lens.OrthographicSize = rate
    end
    self._virtualCamMain.m_Lens = Lens

    self:UpdateCameraInfo()

    self:UpdateCameraPosition()
    self._buildingMgr:IsShowInView(rate)
end


function LCityView:UpdateCameraInfo()
    self._camRatio = 0.01

    local cameraSize = self:GetCameraSize()
    if not cameraSize then return end

    local UScreen = UnityEngine.Screen
    local screenHeight = UScreen.height
    local screenWidth = UScreen.width

    if screenHeight < 0 then return end

    self._camRatio = cameraSize * 2 / screenHeight

    local border = self._border
    if not border then
        self._isLimitBound = false
        return
    end

    self._isLimitBound = true

    local screenHalfSize = Vector2.zero
    screenHalfSize.y = cameraSize
    screenHalfSize.x = screenHalfSize.y * screenWidth / screenHeight

    local bannerX, bannerY = LxUiHelper.GetNotchBannerSize()
    if bannerX > 0 then
        bannerX = bannerX * self._camRatio
    else
        bannerX = 0
    end

    if bannerY > 0 then
        bannerY = bannerY * self._camRatio
    else
        bannerY = 0
    end

    local borderX = border[1]
    local borderY = border[2]
    local xMax = 0.5 * borderX
    local yMax = 0.5 * borderY
    xMax = math.max(0, xMax - screenHalfSize.x + bannerX)
    yMax = math.max(0, yMax - screenHalfSize.y + bannerY)
    local xMin = -xMax
    local yMin = -yMax

    self._camRangX.x = xMin
    self._camRangX.y = xMax
    self._camRangY.x = yMin
    self._camRangY.y = yMax

    local cameraFollow = self._cameraFollow
    cameraFollow.isLimitBounds = true
    cameraFollow.minLimit = Vector3(xMin ,yMin, -9999)
    cameraFollow.maxLimit = Vector3(xMax ,yMax, 9999)
end

function LCityView:ChangeCameraRange(changeValue)
    local newValue = self._curCameraRate + changeValue
    if newValue < self._cameraMinRate then return end
    if newValue > self._cameraMaxRate then return end
    self:UpdateCamRang(newValue)
end

