---相机定位到建筑(1,记录当前缩放;2,移动到目标位置,且修改缩放)
function LCityView:MoveToBuild(buildId,callBack,isRet)
    self:SetFollowNil()
    local radio = 0
    self._curScreen = Vector2(UScreen.width,UScreen.height)
    local nowRate = self._curScreen.x / self._curScreen.y
    local designRate = self._customScreen.x / self._customScreen.y
    if (nowRate >= designRate) then
    else
        radio = nowRate / designRate
    end
    if(radio >= 0.99)then
        --对750*1334特殊处理
        radio = 0
    end
    if(nowRate <= 0.5)then
        --高是宽的二倍还要多
        radio = radio/2
    end

    --记录相机缩放
    local lens = self._virtualCamMain.m_Lens;
    if not isRet then
        self.rememberCameraScale = lens.OrthographicSize;
    end
    --获取目标建筑位置
    local building = self._buildingMgr:GetBuilding(buildId);
    if(building)then
        local config = GameTable.BuildingRef[buildId]
        local data = ModuleCenter.Building:GetBuildingInfo(buildId)
        if(data ~= nil)then
            if(config.maxLevel == 1)then
                --特定种类建筑不进行镜头移动
                if( callBack ~= nil)then
                    callBack();
                end
                return
            end
        end

        local targetPosition = building._buildingTrans.position;
        targetPosition.y = targetPosition.y - (checknumber(config.camerabuildXY))
                + checknumber(config.camerabuildXY)*radio
        local sequene = self:NewTweenSeq(_Tween_ID.cameraMove, function()
            if(self:IsDisposed())then
                return
            end

            self._seqCom:DeleteSeq(_Tween_ID.cameraScale)

        end)
        --移动
        local moveTween = self._virtualCamMainGo.transform:DOMove(targetPosition,self.moveTime);
        moveTween:OnComplete(function()
            if( callBack ~= nil)then
                callBack();
            end
        end)

        if not isRet then
            --缩放
            local scaleTween = LxUiHelper.TweenFloat(self.rememberCameraScale,config.camerabuildRate,self.moveTime * 2, function(val)
                local offsetValue = val - self._curCameraRate
                self._camPosition = self._virtualCamMainGo.transform.position;
                self:ChangeCameraRange(offsetValue);
            end)
            sequene:Append(scaleTween);
        else
            local scaleTween = LxUiHelper.TweenFloat(self.rememberCameraScale,config.camerabuildRate,self.moveTime * 2, function(val)
                local offsetValue = val - self._curCameraRate
                self._camPosition = self._virtualCamMainGo.transform.position;
                self._curCameraRate = self._curCameraRate + offsetValue
            end)
            sequene:Append(scaleTween);
        end
        
        sequene:Join(moveTween);
        sequene:PlayForward();
    end
end
