function LCityView:ResetCameraScale()
    self._resetCameraScale = true
    local lens = self._virtualCamMain.m_Lens;
    local curSize = lens.OrthographicSize;
    local sequene = self:NewTweenSeq(_Tween_ID.cameraReset, function()
        if(self:IsDisposed())then
            return
        end
        self._seqCom:DeleteSeq(_Tween_ID.cameraReset)
        self._resetCameraScale = false
    end)
    local scaleTween = LxUiHelper.TweenFloat(curSize,self.rememberCameraScale,self.moveTime * 2, function(val)
        local offsetValue = val - self._curCameraRate
        self:ChangeCameraRange(offsetValue);
    end)
    sequene:Append(scaleTween);
    sequene:PlayForward();
end
