function LCityView:OnDragMapStart(screenPos)
    CtrlCenter.Guide:StopGuideTip()
    local worldPos = self._virtualCamMainTrans.position
    self._camPosition.x = worldPos.x
    self._camPosition.y = worldPos.y
    self._startDragScreenPos = screenPos
    self._startDragWorldPos.x = worldPos.x
    self._startDragWorldPos.y = worldPos.y
    self:UpdateCameraInfo()
end

function LCityView:OnDragMapEnd(screenPos, deltaPosition)
    local distance =  Vector2.Magnitude(deltaPosition)
    if distance > 5 then
        local moveVec = -(deltaPosition * self._camRatio) * 10
        self._camPosition.x = self._camPosition.x + moveVec.x
        self._camPosition.y = self._camPosition.y + moveVec.y
        if self._isLimitBound then
            self._camPosition.x = Mathf.Clamp(self._camPosition.x, self._camRangX.x, self._camRangX.y)
            self._camPosition.y = Mathf.Clamp(self._camPosition.y, self._camRangY.x, self._camRangY.y)
        end
        self._playCameraTween = true
        local tween = self:NewTweenSeq(_Tween_ID.cameraGOPos,function()
            if self:IsDisposed() then return end
            self._seqCom:DeleteSeq(_Tween_ID.cameraGOPos)
            self._playCameraTween = false
        end)
        local virtualCamMainTrans = self._virtualCamMainTrans
        local pos = virtualCamMainTrans.localPosition
        tween:Append(virtualCamMainTrans:DOLocalMove(Vector3(self._camPosition.x,self._camPosition.y,pos.z),0.5))
        tween:PlayForward()
    end
end

function LCityView:AdjustMapPosition(screenPos)

    self:SetFollowNil()
    local screenVec = self._startDragScreenPos - screenPos
    --print("[当前向量] "..tostring(screenVec).." 当前缩放"..self._camRatio)
    local pos = screenVec * self._camRatio
    self._camPosition.x = self._startDragWorldPos.x + pos.x
    self._camPosition.y = self._startDragWorldPos.y + pos.y

    self:UpdateCameraPosition()
end

function LCityView:UpdateCameraPosition()

    if self._isLimitBound then
        self._camPosition.x = Mathf.Clamp(self._camPosition.x, self._camRangX.x, self._camRangX.y)
        self._camPosition.y = Mathf.Clamp(self._camPosition.y, self._camRangY.x, self._camRangY.y)
    end
    self._virtualCamMainTrans.localPosition = self._camPosition
end

function LCityView:IsCannotPinchScene()
    return self._playAdjustTween
end

function LCityView:CheckNeedAdjust()
    local ramRangX = self._camRangX
    local rangL = ramRangX.x
    local rangR = ramRangX.y

    local camRangY = self._camRangY
    local rangeT = camRangY.x
    local rangeB = camRangY.y

    local newPos = self._camPosition
    local newPosX = newPos.x
    local newPosY = newPos.y
    local lNum = rangL - newPosX
    local rNum = rangR - newPosX
    local limitL = newPosX <= 0 and lNum >= 0 and lNum <= 0.02
    local limitR = newPosX > 0 and rNum >= 0 and rNum <= 0.02
    local tNum = rangeB - newPosY
    local bNum = rangeT - newPosY
    local limitT = newPosY > 0 and tNum >= 0 and tNum <= 0.02
    local limitB = newPosY <= 0 and bNum >= 0 and bNum <= 0.02
    local isHLimit = limitL or limitR
    local isVLimit = limitT or limitB
    local changeNum = 0
    if isHLimit then
        changeNum = 1
    end
    if isVLimit then
        changeNum = changeNum + 1
    end
    if changeNum < 1 then return end

    local doAniNum = 0
    local moveNum = 0.01 * self._curCameraRate
    local moveX
    if limitL then
        doAniNum = 1
        moveX = rangL + moveNum
    elseif limitR then
        doAniNum = 1
        moveX = rangR - moveNum
    end

    local moveY
    if limitT then
        doAniNum = doAniNum + 1
        moveY = rangeB - moveNum
    elseif limitB then
        doAniNum = doAniNum + 1
        moveY = rangeT + moveNum
    end

    if doAniNum < 1 then return end

    self._playCameraTween = true
    local tween = self:NewTweenSeq(_Tween_ID.cameraGOPos,function()
        if self:IsDisposed() then return end
        self._seqCom:DeleteSeq(_Tween_ID.cameraGOPos)
        self._playCameraTween = false
    end)

    moveX = moveX or newPosX
    moveY = moveY or newPosY
    local virtualCamMainTrans = self._virtualCamMainTrans
    local pos = virtualCamMainTrans.localPosition
    tween:Append(virtualCamMainTrans:DOLocalMove(Vector3(moveX,moveY,pos.z),0.5))
    tween:PlayForward()
end

function LCityView:OnClickNpc(go)
    if self._buildingMgr then
        local building = self._buildingMgr:GetBuildingByName(go.name)
        if building then
            building:ExecuteClick()
            return
        end
    end
    if(self._monsterMgr)then
        local arr = string.split(go.name,"_")
        local monster = self._monsterMgr:GetMonsterUnit(checknumber(arr[2]))
        if(monster)then
            monster:ExecuteClick()
            return
        end
    end
    if(self._peopleMgr)then
        local arr = string.split(go.name,"-")
        local people = self._peopleMgr:GetPeopleUnit(checknumber(arr[2]))
        if(people)then
            people:ExecuteClick()
        end

    end
end

