function LCityView:DoStoryCameraMove(pathDataList,callBack)
    self:SetFollowNil()
    local seqCom = self:GetSeqCom()
    seqCom:DeleteSeq(_Tween_ID.cameraGOPos)
    local tween = seqCom:CreateSeq(_Tween_ID.cameraGOPos)
    tween:OnComplete(function()
        if self:IsDisposed() then return end
        self._seqCom:DeleteSeq(_Tween_ID.cameraGOPos)
        self._camPosition.x = self._virtualCamMainTrans.localPosition.x
        self._camPosition.y = self._virtualCamMainTrans.localPosition.y
        if(callBack ~= nil)then
            callBack()
        end
    end
    )
    --local tween = seqCom:CreateSeq(_Tween_ID.cameraGOPos, function()
    --
    --end)
    local virtualCamMainTrans = self._virtualCamMainTrans
    local pos = virtualCamMainTrans.localPosition
    local posZ = pos.z
    for k, v in ipairs(pathDataList) do
        tween:Append(virtualCamMainTrans:DOLocalMove(Vector3(v.x, v.y, posZ),v.time))
    end
    tween:PlayForward()
end

function LCityView:DoStoryCameraScale(scaleDataList)
    local seqCom = self:GetSeqCom()
    seqCom:DeleteSeq(_Tween_ID.cameraScale)
    local tween = seqCom:CreateSeq(_Tween_ID.cameraScale)
    tween:OnComplete(function()
        if self:IsDisposed() then return end
        self._seqCom:DeleteSeq(_Tween_ID.cameraScale)
    end)
    --local tween = seqCom:NewTweenSeq(_Tween_ID.cameraScale, function()
    --    if self:IsDisposed() then return end
    --    self._seqCom:DeleteSeq(_Tween_ID.cameraScale)
    --end)

    local rate = self._curCameraRate

    for k, v in ipairs(scaleDataList) do
        local faceItem = LxUiHelper.TweenFloat(rate, v.scale, v.time, function(value)
            if self:IsDisposed() then return end

            self._curCameraRate = value

            local Lens = self._virtualCamMain.m_Lens
            if Lens.Orthographic then
                Lens.OrthographicSize = value
            end
            self._virtualCamMain.m_Lens = Lens
        end)
        tween:Append(faceItem)
        rate = v.scale
    end
    tween:PlayForward()
end
function LCityView:PeopleQuestion(peopleRefId,questionRefId)
    if(self._peopleQuestionHud)then
        self._peopleQuestionHud:Dispose()
    end
    if(self._peopleQuestionSp)then
        self._peopleQuestionSp:Dispose()
    end
    local peopleRef = GameTable.PeopleRef[peopleRefId]
    local peopleQuestionRef = GameTable.PeopleQuestionRef[questionRefId]
    local index = math.random(1,#peopleQuestionRef.siteXY)
    local peoplePos = peopleQuestionRef.siteXY[index]
    local arr = string.split(peoplePos,",")
    self._peopleQuestionSp = require("LApp.component.dp.LxSpineDp"):new();
    self._peopleQuestionSp:InitDp(peopleRef.model,self._npcRoot.transform)
    self._peopleQuestionSp:SetLocalPosition(Vector3(checknumber(arr[1]),checknumber(arr[2]),0))
    self._peopleQuestionSp:SetScale(peopleRef.scale)
    self._peopleQuestionSp:SetLoadedCallback(function(dp)
        --self:MoveToPeople(pe)
        self:LoadPeopleQuestionCallBack(dp)
    end)
    self._peopleQuestionSp:SetRenderOrder(100)
    self._peopleQuestionSp:Load()
end
function LCityView:LoadPeopleQuestionCallBack(dp)
    self:PeopleQuestionMoveToTransform(dp:GetDpTrans())
    self._peopleQuestionHud = require("LApp.gameplay.city.view.LCityPeopleHud"):new()
    if(self._peopleHudObj == nil)then
        self._peopleHudObj = FindChild(self.hudCanvasRoot,"PeopleHud")
    end
    local hud = InstantObject(self._peopleHudObj)
    hud.transform:SetParent(MgrCenter.UIMgr._hudCanvasTrans)
    PJXUtil.SetLayerMask(hud,"UI")
    hud.transform.localScale = Vector3.one
    self._peopleQuestionHud:SetTransform(dp:GetDpTrans(),hud)
    self._peopleQuestionHud:ShowQuestion()
    ShowObject(hud.gameObject,true)
end
function LCityView:PeopleQuestionEnd()
    if(self._peopleQuestionHud)then
        self._peopleQuestionHud:Dispose()
    end
    if(self._peopleQuestionSp)then
        self._peopleQuestionSp:Dispose()
    end
end
