function LCityView:UsePeopleSkill(skillId)
    local peopleSkillRef = GameTable.PeopleSkillRef[skillId]
    local targetScale = peopleSkillRef.focusRate
    local scaleList = {{scale = targetScale,time = 1}}
    self:DoStoryCameraScale(scaleList)
    local arr = string.split(peopleSkillRef.focusSite,"|")
    local pathList = {}
    for i, v in ipairs(arr) do
        local pathData = string.split(v,"=")
        local order = pathData[1]
        local posData = string.split(pathData[2],",")
        local pos = Vector2(checknumber(posData[1]),checknumber(posData[2]))
        local delay = 0
        if(checknumber(pathData[3]) > 0)then
            delay = checknumber(pathData[3])
        end
        local p = {order = order,pos = pos,delay = delay,time = 1}
        table.insert(pathList,p)
    end
    self:DoPeopleSkillCameraMove(pathList, function()
        if(skillId == 1008)then
            self._buildingMgr:GetBuilding(1006):ShowCityWallEffect()
        end

    end)
    self:BroadcastGpEvent(CityEvent.UsePeopleSkill,{skillId = skillId})
end
function LCityView:DoPeopleSkillCameraMove(pathList,callBack)
    self:SetFollowNil()
    local seqCom = self:GetSeqCom()
    seqCom:DeleteSeq(_Tween_ID.cameraSkillMove)
    local tween = seqCom:CreateSeq(_Tween_ID.cameraSkillMove)
    tween:OnComplete(function()
        if(self:IsDisposed())then
            return
        end
        self._camPosition.x = self._virtualCamMainTrans.localPosition.x;
        self._camPosition.y = self._virtualCamMainTrans.localPosition.y
        if(callBack ~= nil)then
            callBack()
        end
    end)
    local VirtualCameraMainTrans = self._virtualCamMainTrans
    local pos = VirtualCameraMainTrans.localPosition
    local posZ = pos.z
    for i, v in ipairs(pathList) do
        local delay = 0;
        if(i == 1)then
            delay = 0
        else
            delay = pathList[i - 1].delay
        end
        local move = VirtualCameraMainTrans:DOLocalMove(Vector3(v.pos.x,v.pos.y,posZ),v.time):SetDelay(delay)
        tween:Append(move)
    end
    tween:PlayForward()
end
function LCityView:DoStoryCameraFollow(trans,offset,time)
    self:SetFollowNil()
    if(trans == nil)then
        return
    end

    local seqCom = self:GetSeqCom()
    seqCom:DeleteSeq(_Tween_ID.cameraFollowMove)
    local tween = seqCom:CreateSeq(_Tween_ID.cameraFollowMove)
    tween:OnComplete(function()
        self._camPosition.x = self._virtualCamMainTrans.localPosition.x
        self._camPosition.y = self._virtualCamMainTrans.localPosition.y
        self:FollowTarget(trans,offset)
    end)
    local pos = trans.localPosition
    local move = self._virtualCamMainTrans:DOLocalMove(pos,time)
    tween:Append(move)
    tween:PlayForward()
end
