function LCityView:PlayShake(stemShockTime,x,y)
    x = x or 0
    y = y or 0
    local root = self._shakeRoot.transform
    root.localPosition = Vector3.zero
    local pos = Vector3.zero

    local seq = self:NewTweenSeq("PlayShake", function()
        self:GetSeqCom():DeleteSeq("PlayShake")
    end)
    local tweenShake = LxUiHelper.TweenFloat(0, 1, stemShockTime, function(percent)
        local tx, ty = PJXUtil.InsideUnitCircle(0, 0)
        pos.x = tx * x * (1 - percent)
        pos.y = ty * y * (1 - percent)
        root.localPosition = pos
    end)
    seq:Append(tweenShake)
    seq:SetAutoKill(false)
    seq:PlayForward()
end
